/**
 * Generate email_template test data based on pattern
 *
 * @param pattern - The test data pattern to generate
 * @param overrides - Optional field overrides
 * @returns Generated test data
 *
 * @example
 * ```typescript
 * // Generate complete test data
 * const data = generateEmailTemplateTestData('complete');
 *
 * // Generate unique test data with overrides
 * const customData = generateEmailTemplateTestData('unique', {
 *   is_active: false,
 * });
 * ```
 */
export function generateEmailTemplateTestData(
  pattern: TestDataPattern = 'complete',
  overrides: Partial<EmailTemplateCreateRequest> = {}
): EmailTemplateCreateRequest {
  let baseData: EmailTemplateCreateRequest;

  switch (pattern) {
    case 'minimal':
      baseData = { ...minimalEmailTemplateFixture };
      break;

    case 'complete':
      baseData = { ...completeEmailTemplateFixture };
      break;

    case 'invalid':
      // Return invalid data (caller should handle validation failure)
      baseData = { ...invalidEmailTemplateFixture } as EmailTemplateCreateRequest;
      break;

    case 'unique':
      // Generate fresh unique values for each call
      baseData = {
        ...uniqueEmailTemplateFixture,
        name: `Test EmailTemplate ${generateUniqueId()}`,
      };
      break;

    default:
      baseData = { ...completeEmailTemplateFixture };
  }

  return { ...baseData, ...overrides };
}

/**
 * Generate multiple email_template fixtures
 *
 * @param count - Number of fixtures to generate
 * @param pattern - The test data pattern to use as base
 * @param modifier - Optional function to modify each fixture
 * @returns Array of generated test data
 *
 * @example
 * ```typescript
 * // Generate 5 unique fixtures
 * const fixtures = generateMultipleEmailTemplateFixtures(5, 'unique');
 *
 * // Generate fixtures with sequential numbering
 * const numbered = generateMultipleEmailTemplateFixtures(3, 'complete', (data, index) => ({
 *   ...data,
 *   name: `EmailTemplate #${index + 1}`,
 * }));
 * ```
 */
export function generateMultipleEmailTemplateFixtures(
  count: number,
  pattern: TestDataPattern = 'unique',
  modifier?: (data: EmailTemplateCreateRequest, index: number) => EmailTemplateCreateRequest
): EmailTemplateCreateRequest[] {
  const fixtures: EmailTemplateCreateRequest[] = [];

  for (let i = 0; i < count; i++) {
    let fixture = generateEmailTemplateTestData(pattern);

    if (modifier) {
      fixture = modifier(fixture, i);
    } else if (pattern === 'unique') {
      // Add index to ensure uniqueness even with same timestamp
      fixture.name = `Test EmailTemplate ${generateUniqueId()}-${i}`;
    }

    fixtures.push(fixture);
  }

  return fixtures;
}

